import java.util.*;

public class Solution {
    public static long solve(long[] landStartTime, long[] landDuration, long[] waterStartTime, long[] waterDuration) {
        int n = landStartTime.length;
        int m = waterStartTime.length;
        long[] landEnd = new long[n];
        for (int i = 0; i < n; i++) {
            landEnd[i] = landStartTime[i] + landDuration[i];
        }
        long[] waterEnd = new long[m];
        for (int j = 0; j < m; j++) {
            waterEnd[j] = waterStartTime[j] + waterDuration[j];
        }
        Arrays.sort(landEnd);
        Arrays.sort(waterEnd);

        long minOrder1 = Long.MAX_VALUE;
        if (n > 0) {
            long minLandEnd = landEnd[0];
            for (int j = 0; j < m; j++) {
                long waterStart = waterStartTime[j];
                long waterDur = waterDuration[j];
                int idx = Arrays.binarySearch(landEnd, waterStart);
                if (idx < 0) {
                    idx = -idx - 1;
                }
                long candidate1 = Long.MAX_VALUE;
                if (idx < n) {
                    candidate1 = landEnd[idx] + waterDur;
                }
                long candidate2 = Long.MAX_VALUE;
                if (minLandEnd < waterStart) {
                    candidate2 = waterStart + waterDur;
                }
                minOrder1 = Math.min(minOrder1, Math.min(candidate1, candidate2));
            }
        }

        long minOrder2 = Long.MAX_VALUE;
        if (m > 0) {
            long minWaterEnd = waterEnd[0];
            for (int i = 0; i < n; i++) {
                long landStart = landStartTime[i];
                long landDur = landDuration[i];
                int idx = Arrays.binarySearch(waterEnd, landStart);
                if (idx < 0) {
                    idx = -idx - 1;
                }
                long candidate1 = Long.MAX_VALUE;
                if (idx < m) {
                    candidate1 = waterEnd[idx] + landDur;
                }
                long candidate2 = Long.MAX_VALUE;
                if (minWaterEnd < landStart) {
                    candidate2 = landStart + landDur;
                }
                minOrder2 = Math.min(minOrder2, Math.min(candidate1, candidate2));
            }
        }

        return Math.min(minOrder1, minOrder2);
    }
}
